pub fn dispatch_runtime_call(
	dispatcher: &mut impl RuntimeCallDispatcher, call: GlorpCall,
) -> Result<GlorpCallResult, GlorpError> {
	match call.id.as_str() {
		"txn" => calls::Txn::respond(dispatcher.txn(calls::Txn::decode_call_input(&call)?)?),
		"config-set" => calls::ConfigSet::respond(dispatcher.config_set(calls::ConfigSet::decode_call_input(&call)?)?),
		"config-reset" => {
			calls::ConfigReset::respond(dispatcher.config_reset(calls::ConfigReset::decode_call_input(&call)?)?)
		}
		"config-patch" => {
			calls::ConfigPatch::respond(dispatcher.config_patch(calls::ConfigPatch::decode_call_input(&call)?)?)
		}
		"config-reload" => {
			calls::ConfigReload::respond(dispatcher.config_reload(calls::ConfigReload::decode_call_input(&call)?)?)
		}
		"config-persist" => {
			calls::ConfigPersist::respond(dispatcher.config_persist(calls::ConfigPersist::decode_call_input(&call)?)?)
		}
		"document-replace" => calls::DocumentReplace::respond(
			dispatcher.document_replace(calls::DocumentReplace::decode_call_input(&call)?)?,
		),
		"editor-motion" => {
			calls::EditorMotion::respond(dispatcher.editor_motion(calls::EditorMotion::decode_call_input(&call)?)?)
		}
		"editor-mode" => {
			calls::EditorMode::respond(dispatcher.editor_mode(calls::EditorMode::decode_call_input(&call)?)?)
		}
		"editor-insert" => {
			calls::EditorInsert::respond(dispatcher.editor_insert(calls::EditorInsert::decode_call_input(&call)?)?)
		}
		"editor-backspace" => calls::EditorBackspace::respond(
			dispatcher.editor_backspace(calls::EditorBackspace::decode_call_input(&call)?)?,
		),
		"editor-delete-forward" => calls::EditorDeleteForward::respond(
			dispatcher.editor_delete_forward(calls::EditorDeleteForward::decode_call_input(&call)?)?,
		),
		"editor-delete-selection" => calls::EditorDeleteSelection::respond(
			dispatcher.editor_delete_selection(calls::EditorDeleteSelection::decode_call_input(&call)?)?,
		),
		"editor-history" => {
			calls::EditorHistory::respond(dispatcher.editor_history(calls::EditorHistory::decode_call_input(&call)?)?)
		}
		"schema" => calls::Schema::respond(dispatcher.schema(calls::Schema::decode_call_input(&call)?)?),
		"config" => calls::Config::respond(dispatcher.config(calls::Config::decode_call_input(&call)?)?),
		"document-text" => {
			calls::DocumentText::respond(dispatcher.document_text(calls::DocumentText::decode_call_input(&call)?)?)
		}
		"editor" => calls::Editor::respond(dispatcher.editor(calls::Editor::decode_call_input(&call)?)?),
		"capabilities" => {
			calls::Capabilities::respond(dispatcher.capabilities(calls::Capabilities::decode_call_input(&call)?)?)
		}
		"session-attach" => Err(route_dispatch_error(&call.id, GlorpCallRoute::Runtime)),
		"session-shutdown" => Err(route_dispatch_error(&call.id, GlorpCallRoute::Runtime)),
		"config-validate" => Err(route_dispatch_error(&call.id, GlorpCallRoute::Runtime)),
		"events-subscribe" => calls::EventsSubscribe::respond(
			dispatcher.events_subscribe(calls::EventsSubscribe::decode_call_input(&call)?)?,
		),
		"events-next" => {
			calls::EventsNext::respond(dispatcher.events_next(calls::EventsNext::decode_call_input(&call)?)?)
		}
		"events-unsubscribe" => calls::EventsUnsubscribe::respond(
			dispatcher.events_unsubscribe(calls::EventsUnsubscribe::decode_call_input(&call)?)?,
		),
		_ => Err(unknown_call(&call.id)),
	}
}

