pub fn call_specs() -> &'static [GlorpCallSpec] {
	CALL_SPECS.as_slice()
}

pub fn call_spec(id: &str) -> Option<&'static GlorpCallSpec> {
	call_specs().iter().find(|spec| spec.id == id)
}

pub fn call_ids() -> Vec<String> {
	call_specs().iter().map(|call| call.id.clone()).collect()
}

